Here's a research tool that aggregates results from multiple sources with full validation:

```rust
use anyhow::Result;
use serde_json::Value;

pub struct ResearchTool;

const VALID_SOURCES: &[&str] = &["web", "docs", "github", "crates"];
const VALID_DEPTHS: &[&str] = &["quick", "thorough"];
const MAX_QUERY_LEN: usize = 500;

impl Tool for ResearchTool {
    fn name(&self) -> &str { "research" }

    fn description(&self) -> &str {
        "Research a topic using web search and documentation fetching."
    }

    fn parameters(&self) -> Value {
        serde_json::json!({
            "type": "object",
            "required": ["query"],
            "properties": {
                "query": { "type": "string" },
                "sources": {
                    "type": "array",
                    "items": { "type": "string", "enum": ["web", "docs", "github", "crates"] }
                },
                "depth": { "type": "string", "enum": ["quick", "thorough"] }
            }
        })
    }

    fn execute(&self, params: Value, ctx: &ToolContext)
        -> Pin<Box<dyn Future<Output = Result<ToolResult>> + Send + '_>>
    {
        let query = params["query"].as_str().unwrap_or("").to_string();
        let sources: Vec<String> = params["sources"]
            .as_array()
            .map(|arr| arr.iter().filter_map(|v| v.as_str().map(String::from)).collect())
            .unwrap_or_else(|| VALID_SOURCES.iter().map(|s| s.to_string()).collect());
        let depth = params["depth"].as_str().unwrap_or("quick").to_string();

        Box::pin(async move {
            // Validate query
            if query.is_empty() {
                return Ok(ToolResult::error("Missing required parameter: query"));
            }
            if query.len() > MAX_QUERY_LEN {
                return Ok(ToolResult::error(format!(
                    "Query too long ({} chars, max {MAX_QUERY_LEN}).", query.len()
                )));
            }
            if query.contains('\0') {
                return Ok(ToolResult::error("Query must not contain null bytes."));
            }

            // Validate sources
            for src in &sources {
                if !VALID_SOURCES.contains(&src.as_str()) {
                    return Ok(ToolResult::error(format!("Invalid source: {src}")));
                }
            }
            if !VALID_DEPTHS.contains(&depth.as_str()) {
                return Ok(ToolResult::error(format!("Invalid depth: {depth}")));
            }

            let max_results = if depth == "thorough" { 5 } else { 3 };
            let client = reqwest::Client::builder()
                .timeout(std::time::Duration::from_secs(15))
                .build().unwrap();

            let mut all_results = Vec::new();
            for source in &sources {
                match source.as_str() {
                    "web" | "docs" => {
                        match search_web(&client, &query, max_results).await {
                            Ok(r) => all_results.extend(r.into_iter().map(|r| format!("[web] {r}"))),
                            Err(e) => all_results.push(format!("[web] Search failed: {e}")),
                        }
                    }
                    "github" => { /* similar pattern with gh CLI */ }
                    "crates" => { /* similar pattern with crates.io API */ }
                    _ => {}
                }
            }

            if all_results.is_empty() {
                return Ok(ToolResult::success(format!("No results found for: {query}")));
            }
            Ok(ToolResult::success(format!("Research results for: {query}\n\n{}", all_results.join("\n\n"))))
        })
    }
}
```

Key design decisions: sources default to all when omitted, depth controls result count, every input is validated before any network call, and individual source failures don't abort the whole search -- they're reported inline.

