Sanitize the query to alphanumeric + safe chars, use `tokio::process::Command` with explicit args (never shell interpolation), and wrap in `tokio::time::timeout`:

```rust
async fn search_github(
    query: &str,
    max_results: usize,
    project_path: &std::path::Path,
) -> Result<Vec<String>> {
    // Strip shell metacharacters -- only allow safe chars
    let safe_query: String = query
        .chars()
        .filter(|c| c.is_alphanumeric() || *c == ' ' || *c == '-' || *c == '_' || *c == '.')
        .collect();

    let output = tokio::time::timeout(
        std::time::Duration::from_secs(10),
        Command::new("gh")
            .args(["search", "repos", &safe_query, "--limit", &max_results.to_string(), "--json", "name,description,url"])
            .current_dir(project_path)
            .stdout(Stdio::piped())
            .stderr(Stdio::piped())
            .output(),
    )
    .await;

    match output {
        Ok(Ok(out)) => {
            if !out.status.success() {
                let stderr = String::from_utf8_lossy(&out.stderr);
                return Ok(vec![format!("gh search failed: {stderr}")]);
            }
            let stdout = String::from_utf8_lossy(&out.stdout);
            match serde_json::from_str::<Vec<Value>>(&stdout) {
                Ok(repos) => Ok(repos.iter().take(max_results).map(|r| {
                    let name = r["name"].as_str().unwrap_or("?");
                    let desc = r["description"].as_str().unwrap_or("(no description)");
                    let url = r["url"].as_str().unwrap_or("");
                    format!("{name} -- {desc}\n  {url}")
                }).collect()),
                Err(_) => Ok(vec!["Failed to parse gh output".to_string()]),
            }
        }
        Ok(Err(e)) => Ok(vec![format!("gh not available: {e}")]),
        Err(_) => Ok(vec!["GitHub search timed out".to_string()]),
    }
}
```

Three layers of defense: (1) character-level sanitization removes `;`, `&`, `|`, `$` etc., (2) `Command::new` with `.args()` never passes through a shell so no metachar expansion, (3) the 10-second timeout prevents hangs if `gh` blocks on auth prompts. Security tests should verify that metacharacters like `; rm -rf /` get stripped.

