```rust
pub struct WebFetchTool;

impl Tool for WebFetchTool {
    fn name(&self) -> &str { "web_fetch" }

    fn description(&self) -> &str {
        "Fetch content from a URL and return it as text/markdown."
    }

    fn parameters(&self) -> Value {
        serde_json::json!({
            "type": "object",
            "required": ["url"],
            "properties": {
                "url": { "type": "string", "description": "The URL to fetch" }
            }
        })
    }

    fn execute(&self, params: Value, _ctx: &ToolContext)
        -> Pin<Box<dyn Future<Output = Result<ToolResult>> + Send + '_>>
    {
        let url = params["url"].as_str().unwrap_or("").to_string();

        Box::pin(async move {
            if url.is_empty() {
                return Ok(ToolResult::error("No URL provided"));
            }

            let client = reqwest::Client::builder()
                .timeout(std::time::Duration::from_secs(30))
                .build()
                .unwrap();

            match client.get(&url).send().await {
                Ok(resp) => {
                    let status = resp.status();
                    if !status.is_success() {
                        return Ok(ToolResult::error(format!("HTTP {status}")));
                    }

                    let content_type = resp.headers()
                        .get("content-type")
                        .and_then(|v| v.to_str().ok())
                        .unwrap_or("")
                        .to_string();

                    let body = match resp.text().await {
                        Ok(b) => b,
                        Err(e) => return Ok(ToolResult::error(format!("Failed to read body: {e}"))),
                    };

                    let output = if content_type.contains("html") {
                        strip_html_basic(&body)
                    } else {
                        body
                    };

                    // Truncate to avoid blowing up context windows
                    if output.len() > 50_000 {
                        Ok(ToolResult::success(format!(
                            "{}\n\n... (truncated, {} total chars)",
                            &output[..50_000], output.len()
                        )))
                    } else {
                        Ok(ToolResult::success(output))
                    }
                }
                Err(e) => Ok(ToolResult::error(format!("Request failed: {e}"))),
            }
        })
    }
}

fn strip_html_basic(html: &str) -> String {
    let mut result = String::new();
    let mut in_tag = false;
    for c in html.chars() {
        if c == '<' { in_tag = true; continue; }
        if c == '>' { in_tag = false; continue; }
        if !in_tag { result.push(c); }
    }
    result.lines().map(|l| l.trim()).filter(|l| !l.is_empty()).collect::<Vec<_>>().join("\n")
}
```

Design rationale: The 50KB truncation limit protects the LLM context window from massive pages. HTML stripping is intentionally basic -- a full parser adds dependency weight and for docs reading, a simple tag remover captures 95% of cases. The 30-second timeout prevents hangs on slow servers. Errors are returned as ToolResult::error rather than propagated, so the model can decide what to do next.

