Use `dlopen`/`dlsym` with `unsafeBitCast` to get typed function pointers. Define the expected C-compatible signatures and load them at init time:

```swift
@MainActor
class RTAIBridge: ObservableObject {
    private var libraryHandle: UnsafeMutableRawPointer?
    private var isInitialized = false

    // Function pointers matching Rust's #[no_mangle] extern "C" fns
    private var rtai_init: (@convention(c) (Int32, UInt8, UInt8, UInt64) -> UInt8)?
    private var rtai_start: (@convention(c) () -> UInt8)?
    private var rtai_shutdown: (@convention(c) () -> UInt8)?
    private var rtai_health_check: (@convention(c) () -> UInt8)?
    private var rtai_process_text: UnsafeMutableRawPointer?
    private var rtai_free_result: UnsafeMutableRawPointer?

    init() {
        loadLibrary()
    }

    private func loadLibrary() {
        let paths = [
            Bundle.main.resourceURL?.appendingPathComponent("Libraries/libfolktech_rtai.dylib").path,
            "/usr/local/lib/libfolktech_rtai.dylib",
            "/opt/homebrew/lib/libfolktech_rtai.dylib",
        ].compactMap { $0 }

        for path in paths {
            if let handle = dlopen(path, RTLD_NOW) {
                libraryHandle = handle
                loadFunctionPointers()
                return
            }
        }
    }

    private func loadFunctionPointers() {
        guard let handle = libraryHandle else { return }
        if let ptr = dlsym(handle, "rtai_init") {
            rtai_init = unsafeBitCast(ptr, to: (@convention(c) (Int32, UInt8, UInt8, UInt64) -> UInt8).self)
        }
        if let ptr = dlsym(handle, "rtai_start") {
            rtai_start = unsafeBitCast(ptr, to: (@convention(c) () -> UInt8).self)
        }
        // ... same pattern for other functions
    }

    deinit {
        if let shutdown = rtai_shutdown { _ = shutdown() }
        if let handle = libraryHandle { dlclose(handle) }
    }
}
```

Key gotchas: Rust `bool` is 1 byte, so use `UInt8` on the Swift side, not `Bool`. For functions that return structs, keep the raw pointer and use `unsafeBitCast` with the specific calling convention. Always call the Rust `free` function for any allocated result pointers to avoid leaks.

Read the struct field-by-field using byte offset loads, matching the Rust struct's memory layout:

```swift
func processText(_ input: String) async -> RTAIProcessingResult {
    guard let processFunc = rtai_process_text else {
        return RTAIProcessingResult(success: false, response: "", processingTimeMs: 0, confidence: 0.0, errorMessage: "Library not loaded")
    }

    let result = input.withCString { inputPtr -> (success: Bool, response: String, confidence: Double) in
        // CRTAIResult layout on 64-bit:
        // offset 0:  u8 success + 7 bytes padding
        // offset 8:  *const c_char response
        // offset 16: u64 processing_time_ms
        // offset 24: f64 confidence
        // offset 32: *const c_char error
        // Total: 40 bytes

        typealias ProcessFn = @convention(c) (UnsafePointer<CChar>) -> UnsafeMutableRawPointer
        let rustProcess = unsafeBitCast(processFunc, to: ProcessFn.self)
        let resultPtr = rustProcess(inputPtr)

        let success = resultPtr.load(fromByteOffset: 0, as: UInt8.self) != 0
        let responsePtr = resultPtr.load(fromByteOffset: 8, as: UnsafePointer<CChar>?.self)
        let confidence = resultPtr.load(fromByteOffset: 24, as: Double.self)

        var response = ""
        if let rPtr = responsePtr {
            response = String(cString: rPtr)
        }

        // CRITICAL: free the Rust-allocated result
        if let freeFunc = self.rtai_free_result {
            typealias FreeFn = @convention(c) (UnsafeMutableRawPointer) -> Void
            let rustFree = unsafeBitCast(freeFunc, to: FreeFn.self)
            rustFree(resultPtr)
        }

        return (success, response, confidence)
    }

    return RTAIProcessingResult(
        success: result.success,
        response: result.response,
        processingTimeMs: 0,
        confidence: result.confidence,
        errorMessage: nil
    )
}
```

The byte offsets must exactly match the Rust struct layout with C repr. If the Rust side changes, this breaks silently -- consider adding a version check function that returns the struct size so you can assert at init time.

