The key insight is early rejection of queries that should always go to the LLM, then a tiered waterfall:

```swift
func processText(_ input: String, context: [Message] = []) async -> RTAIProcessingResult {
    let lowerInput = input.lowercased()

    // TIER 0: Early rejection -- help/conversational queries bypass all tiers
    let helpIndicators = [
        "help me", "build a", "write a", "how do i", "explain how",
        "create a", "implement", "debug", "fix my"
    ]
    for indicator in helpIndicators {
        if lowerInput.contains(indicator) {
            return RTAIProcessingResult(success: false, response: "", processingTimeMs: 0, confidence: 0.0, errorMessage: nil)
        }
    }

    let startTime = CFAbsoluteTimeGetCurrent()

    // TIER 1: Rust RTAI library (fastest, loads .ftai fact files)
    if let rustResult = tryRustBackend(input) {
        if rustResult.confidence >= 0.80 && !rustResult.response.isEmpty {
            let ms = UInt64((CFAbsoluteTimeGetCurrent() - startTime) * 1000)
            return RTAIProcessingResult(success: true, response: rustResult.response, processingTimeMs: ms, confidence: rustResult.confidence, errorMessage: nil)
        }
    }

    // TIER 1.5: Swift FTAI parser (knowledge base lookup)
    if swiftFTAIParser.isInitialized {
        let ftaiResult = swiftFTAIParser.lookup(input)
        if ftaiResult.confidence >= 0.80 {
            let ms = UInt64((CFAbsoluteTimeGetCurrent() - startTime) * 1000)
            return RTAIProcessingResult(success: true, response: ftaiResult.response, processingTimeMs: ms, confidence: ftaiResult.confidence, errorMessage: nil)
        }
    }

    // TIER 2: Mitosis learned patterns (adaptive responses from past interactions)
    if FeatureFlags.mitosisEnabled {
        if let patternResult = mitosisIntegration.findMatch(for: input) {
            if patternResult.confidence >= 0.75 {
                return RTAIProcessingResult(success: true, response: patternResult.response, processingTimeMs: 0, confidence: patternResult.confidence, errorMessage: nil)
            }
        }
    }

    // TIER 3: Fall through to LLM
    return RTAIProcessingResult(success: false, response: "", processingTimeMs: 0, confidence: 0.0, errorMessage: nil)
}
```

Design rationale: Each tier is cheaper than the next (Rust FFI < Swift lookup < pattern match < LLM call). The 0.80 confidence threshold prevents low-quality fast answers from bypassing the LLM. The help-indicator check runs first because those queries are never answerable by fact lookup -- they need generative responses. Returning `success: false` signals the caller to route to the LLM.

