// In RTAIManager:
func getExecutionStats() -> RTAIStats {
    let total = executionHistory.count
    let avgDuration = executionHistory.isEmpty
        ? 0
        : executionHistory.map(\.duration).reduce(0, +) / Double(total)

    let taskTypes = Dictionary(grouping: executionHistory, by: { $0.task.taskId })
    let mostCommon = taskTypes.max(by: { $0.value.count < $1.value.count })?.key ?? "none"

    return RTAIStats(
        totalExecutions: total,
        averageDuration: avgDuration,
        mostCommonTask: mostCommon,
        successRate: 1.0  // Track failures when you add error handling
    )
}
```

The `Dictionary(grouping:by:)` pattern is efficient for finding the most common task. For production, add a `success: Bool` field to `RTAIExecution` and compute the real success rate from the ratio of successful entries.

