    func initialize(maxCells: Int = 8) -> Bool {
        guard !isInitialized else { return true }

        // Try Rust library first
        var rustReady = false
        if let initFunc = rtai_init {
            let result = initFunc(Int32(maxCells), 1, 1, 1000)
            rustReady = result != 0
        }

        // Always initialize Swift fallback
        let swiftReady = swiftFTAIParser.initialize()

        // System is ready if either backend works
        isInitialized = true
        isStarted = true

        if rustReady {
            print("RTAI ready: Rust + Swift")
        } else if swiftReady {
            print("RTAI ready: Swift fallback (\(swiftFTAIParser.factCount) facts)")
        } else {
            print("RTAI ready: pattern matching only")
        }

        return true
    }

    func shutdown() -> Bool {
