Use conditional compilation for platform-specific paths and the right `which`/`where` command:

```rust
fn probe_llamacpp() -> (bool, Option<String>) {
    let candidates: &[&str] = if cfg!(windows) {
        &["llama-server.exe", "llama-server"]
    } else {
        &[
            "llama-server",
            "/usr/local/bin/llama-server",
            "/opt/homebrew/bin/llama-server",
        ]
    };

    let which_cmd = if cfg!(windows) { "where" } else { "which" };

    for candidate in candidates {
        // Try which/where first (finds PATH entries)
        if let Ok(output) = std::process::Command::new(which_cmd)
            .arg(candidate)
            .output()
        {
            if output.status.success() {
                let path = String::from_utf8_lossy(&output.stdout)
                    .lines()
                    .next()
                    .unwrap_or("")
                    .trim()
                    .to_string();
                if !path.is_empty() {
                    return (true, Some(format!("at {path}")));
                }
            }
        }
        // Try direct path existence check (for absolute paths)
        let path = std::path::Path::new(candidate);
        if path.exists() {
            return (true, Some(format!("at {}", path.display())));
        }
    }

    (false, Some("llama-server not found in PATH".to_string()))
}
```

Two detection methods because `which` only finds PATH entries, not absolute paths. On macOS, Homebrew installs to `/opt/homebrew/bin/` which might not be in PATH during a launchd/systemd context. The reason string always reports where the binary was found, so `forge doctor` output is actionable.

