private func rtaiBridgeDebugLog(_ message: String) {
    guard DebugSettings.fileLoggingEnabled else { return }
    let logPath = NSHomeDirectory() + "/Documents/serena_rtai_bridge_debug.log"
    let timestamp = ISO8601DateFormatter().string(from: Date())
    let logLine = "[\(timestamp)] \(message)\n"
    guard let logData = logLine.data(using: .utf8) else { return }
    if let handle = FileHandle(forWritingAtPath: logPath) {
        handle.seekToEndOfFile()
        handle.write(logData)
        handle.closeFile()
    } else {
        FileManager.default.createFile(atPath: logPath, contents: logData)
    }
}
```

Why file-based instead of `os.log`?

1. **Rust FFI debugging**: When the Rust dylib crashes or returns garbage, Console.app logs might not capture the state leading up to it. File logs persist across crashes.

2. **Production safety**: The `DebugSettings.fileLoggingEnabled` guard means zero cost in production -- the function returns immediately without touching the filesystem.

3. **Append-only**: Using `seekToEndOfFile()` + `write()` avoids rewriting the whole file. For a debug session, this is fast enough.

4. **Auto-create**: If the file doesn't exist, `createFile(atPath:contents:)` creates it with the first log line. No setup required.

Use this alongside `os.log` for different purposes: `os.log` for structured logging visible in Console.app, file logging for raw debugging traces you can `tail -f` in Terminal while testing the Rust bridge.

```swift
@MainActor
class RTAIManager: ObservableObject {
    static let shared = RTAIManager()

    @Published private(set) var isProcessing = false
    private let rtaiBridge = RTAIBridge.shared

    /// Check if input should be processed by RTAI
    func isRTAITask(_ input: String) -> Bool {
        let config = SerenaConfig.shared
        guard config.features.rtaiEnabled else { return false }
        return true  // RTAI handles all inputs; confidence decides if result is used
    }

    /// Handle input -- try RTAI first, throw on low confidence to trigger LLM fallback
    func handle(_ input: String) async throws -> String {
        let rtaiResult = await rtaiBridge.processText(input)

        if rtaiResult.success && rtaiResult.confidence >= 0.80 && !rtaiResult.response.isEmpty {
            // High confidence -- use RTAI response directly
            if let task = parseRTAITask(input) {
                let executionId = register(task)
                logExecution(executionId: executionId, task: task, result: rtaiResult.response)
            }
            return rtaiResult.response
        } else if rtaiResult.success {
            // Low confidence -- fall back to LLM
            throw SerenaError.invalidFTAIFormat("RTAI confidence too low")
        } else {
            // RTAI processing failed -- try structured task parsing
            guard let task = parseRTAITask(input) else {
                throw SerenaError.invalidFTAIFormat("Invalid RTAI task format")
            }
            let executionId = register(task)
            let result = try await executeEnhanced(executionId: executionId, task: task)
            logExecution(executionId: executionId, task: task, result: result)
            return result
        }
    }
}
```

The three-branch pattern is intentional: success + high confidence = use directly, success + low confidence = LLM does better, failure = try structured parsing as last resort before throwing. The caller catches the throw and routes to the LLM. This means RTAI never blocks the user from getting an answer -- it either accelerates the response or steps aside.

Return an informative error as a tool result, not a crash. The model can then suggest installation:

```rust
async fn search_github(
    query: &str,
    max_results: usize,
    project_path: &std::path::Path,
) -> Result<Vec<String>> {
    let safe_query: String = query
        .chars()
        .filter(|c| c.is_alphanumeric() || *c == ' ' || *c == '-' || *c == '_' || *c == '.')
        .collect();

    let output = tokio::time::timeout(
        std::time::Duration::from_secs(10),
        Command::new("gh")
            .args(["search", "repos", &safe_query, "--limit", &max_results.to_string()])
            .stdout(Stdio::piped())
            .stderr(Stdio::piped())
            .output(),
    )
    .await;

    match output {
        Ok(Ok(out)) if out.status.success() => {
            // Parse and return results
            parse_gh_output(&out.stdout, max_results)
        }
        Ok(Ok(out)) => {
            let stderr = String::from_utf8_lossy(&out.stderr);
            Ok(vec![format!("gh search failed: {stderr}")])
        }
        Ok(Err(e)) => {
            // This is the "not installed" case -- io::Error with NotFound
            Ok(vec![format!("gh CLI not available: {e}. Install with: brew install gh")])
        }
        Err(_) => Ok(vec!["GitHub search timed out after 10s".to_string()]),
    }
}
```

The `Ok(Err(e))` branch catches the `io::ErrorKind::NotFound` that occurs when the binary doesn't exist. By returning it as a search result string rather than propagating, the research tool continues checking other sources (web, crates.io) and the model gets context about what failed. The model can then tell the user: "GitHub search unavailable -- install `gh` with `brew install gh` for repository search."
